<?php require_once __DIR__.'/../app/poster.php'; $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf(); foreach(['blog_id','atompub_url','livedoor_id','api_password','auth_method'] as $k) if(isset($_POST[$k])&&$_POST[$k]!=='********') set_setting($k,(string)$_POST[$k]); if(isset($_POST['test'])){try{ $msg=livedoor_connection_test(); }catch(Throwable $e){$msg=$e->getMessage();}}} admin_header('livedoor設定'); if($msg)echo'<p class=notice>'.e($msg).'</p>'; echo'<form method=post><h3 class=section-title>接続設定</h3><p class=section-lead>livedoor BlogのAtomPub投稿先と認証情報を入力してください。保存前後に接続テストで確認できます。</p><input type=hidden name=csrf value='.csrf_token().'><div class=form-grid><label>ブログID<input name=blog_id placeholder="ブログの識別ID" value="'.e(setting('blog_id','')).'"></label><label>AtomPub投稿URL<input name=atompub_url placeholder="https://livedoor.blogcms.jp/atompub/{BLOG_NAME}/article" value="'.e(setting('atompub_url','')).'"></label><label>livedoor ID<input name=livedoor_id placeholder="ログインID" value="'.e(setting('livedoor_id','')).'"></label><label>AtomPub用パスワード / APIキー<input type=password name=api_password value="********"></label><label>認証方式<select name=auth_method><option value=basic>Basic</option><option value=wsse '.(setting('auth_method')==='wsse'?'selected':'').'>WSSE</option></select></label></div><p class=muted>パスワード欄の「********」は保存済みの値を表します。変更しない場合はそのまま保存できます。</p><div class=actions><button>保存</button><button name=test value=1>接続テスト</button></div></form>'; admin_footer();
